/* Evidence: cmem-opaque-structure-evolution-9pq7nr */
/* Browser practice: PicoC 3.2.2 C89/C90 plus selected C99. */
/* Changed case 9408; native C23 claims require explicit transfer gates. */
#include <stdio.h>
#include <stdlib.h>
#include <string.h>


struct packet_model { int tag; size_t count; int payload[4]; };

static int evidence_cmem_opaque_structure_evolution_9pq7nr(const struct packet_model *packet, int *sum) {
  size_t index;
  int total = 0;
  if (packet == NULL || sum == NULL || packet->tag != 1 || packet->count > 4) return 0;
  for (index = 0; index < packet->count; ++index) total += packet->payload[index];
  *sum = total;
  return 1;
}

int main(void) {
  struct packet_model packet = { 1, 3, { 4, 5, 6, 0 } };
  int sum = 0;
  int accepted = evidence_cmem_opaque_structure_evolution_9pq7nr(&packet, &sum);
  packet.tag = 9;
  int rejected = evidence_cmem_opaque_structure_evolution_9pq7nr(&packet, &sum);
  int invariant = accepted && !rejected && sum == 15;
  printf("packet sum=%d invariant=%d\n", sum, invariant);
  return invariant ? 0 : 1;
}
